public class InventoryService { public bool Reserve(string sku) => true; }
public class BillingService { public bool Charge(string userId, decimal amount) => true; }
public class ShippingService { public string CreateShipment(string sku) => "SHIP-1"; }

public class CheckoutFacade {
  private readonly InventoryService _inventory = new InventoryService();
  private readonly BillingService _billing = new BillingService();
  private readonly ShippingService _shipping = new ShippingService();

  public string Checkout(string userId, string sku, decimal amount) {
    if (!_inventory.Reserve(sku)) throw new InvalidOperationException("No stock");
    if (!_billing.Charge(userId, amount)) throw new InvalidOperationException("Payment failed");
    return _shipping.CreateShipment(sku);
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Checkout_ReturnsShipmentId() {
  var facade = new CheckoutFacade();
  var shipmentId = facade.Checkout("u1", "sku-1", 100m);
  Assert.IsTrue(shipmentId.StartsWith("SHIP-"));
}

[TestMethod]
public void Checkout_EncapsulatesSubsystemCalls() {
  var facade = new CheckoutFacade();
  Assert.IsNotNull(facade.Checkout("u2", "sku-2", 50m));
}
